import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart({ range }) {
    const svgRef = useRef();

    useEffect(() => {
        if (!svgRef.current) return;

        axios.get('http://localhost:3001/api/uastl').then(res => {
            let data = res.data;
            if (!data || data.length === 0) return;

            // 應用range過濾
            if (range && range.length === 2) {
                data = data.slice(range[0], range[1] + 1);
            }

            const container = d3.select(svgRef.current.parentNode);
            const containerWidth = svgRef.current.parentNode.clientWidth;
            const containerHeight = svgRef.current.parentNode.clientHeight;

            // 清除舊的圖表
            d3.select(svgRef.current).selectAll("*").remove();

            // 創建 SVG 元素
            const svg = d3.select(svgRef.current)
                .attr("width", containerWidth)
                .attr("height", containerHeight);

            // 獲取參數
            const seasonalKeys = Object.keys(data[0]).filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const numSamples = data[0].num_samples_added || 3;
            const p_used = data[0].p_used ? data[0].p_used.split(',').map(Number) : [7, 90, 365];
            const coPoint = data[0].coPoint_used ? +data[0].coPoint_used - 1 : null;

            // 設置顏色常數
            const colors = {
                input: "#4285F4",       // 藍色
                trend: "#DB4437",       // 紅色
                seasonal1: "#F4B400",   // 黃色
                seasonal2: "#0F9D58",   // 綠色
                seasonal3: "#9C27B0",   // 紫色
                residual: "#FF9800"     // 橙色
            };

            // 定義 sigma 範圍
            const sigmaLevels = {
                '50%': 0.674490,
                '99%': 2.575829
            };

            const isoColors = {
                '50%': 'skyblue',
                '99%': 'lightblue'
            };

            const meanColor = 'navy';
            const sampleColors = ['#e74c3c', '#3498db', '#2ecc71', '#f39c12', '#9b59b6'];

            // 構建各個組件
            const components = [
                {
                    key: 'input',
                    name: "Input Data",
                    data: data.map(d => ({
                        mean: +d.input_mean,
                        std: +d.input_std,
                        sample1: +d.sample1_input,
                        sample2: +d.sample2_input,
                        sample3: +d.sample3_input,
                        corr: +d.corr_input
                    }))
                },
                {
                    key: 'trend',
                    name: "Trend Component",
                    data: data.map(d => ({
                        mean: +d.trend_mean,
                        std: +d.trend_std,
                        sample1: +d.sample1_trend,
                        sample2: +d.sample2_trend,
                        sample3: +d.sample3_trend,
                        corr: +d.corr_trend
                    }))
                }
            ];

            // 添加季節性組件
            seasonalKeys.forEach((key, i) => {
                const seasonalNum = key.replace('seasonal', '').replace('_mean', '');
                components.push({
                    key: `seasonal${seasonalNum}`,
                    name: `Seasonal Component ${seasonalNum} (p=${p_used[i] || 'N/A'})`,
                    data: data.map(d => ({
                        mean: +d[`seasonal${seasonalNum}_mean`],
                        std: +d[`seasonal${seasonalNum}_std`],
                        sample1: +d[`sample1_seasonal${seasonalNum}`],
                        sample2: +d[`sample2_seasonal${seasonalNum}`],
                        sample3: +d[`sample3_seasonal${seasonalNum}`],
                        corr: +d[`corr_seasonal${seasonalNum}`]
                    }))
                });
            });

            // 添加殘差組件
            components.push({
                key: 'residual',
                name: "Residual Component",
                data: data.map(d => ({
                    mean: +d.residual_mean,
                    std: +d.residual_std,
                    sample1: +d.sample1_residual,
                    sample2: +d.sample2_residual,
                    sample3: +d.sample3_residual,
                    corr: +d.corr_residual
                }))
            });

            console.log('Components:', components);

            // 計算每個子圖的高度和邊距
            const margin = { top: 50, right: 20, bottom: 60, left: 60 };
            const numComponents = components.length;
            const subPlotHeight = (containerHeight - margin.top - margin.bottom) / numComponents - 10;

            // 創建 x 軸比例尺（時間索引）
            const xScale = d3.scaleLinear()
                .domain([0, data.length - 1])
                .range([margin.left, containerWidth - margin.right]);

            // 創建紅藍色色彩映射 (coolwarm效果)
            const coolWarmColorScale = d3.scaleSequential(d3.interpolateRdBu)
                .domain([1, -1]); // 注意：紅藍色彩需要反轉域

            // 添加主標題
            svg.append("text")
                .attr("x", containerWidth / 2)
                .attr("y", 25)
                .attr("text-anchor", "middle")
                .style("font-size", "16px")
                .style("font-weight", "bold")
                .text("UASTL Decomposition Results (Python Replica)");

            // 為每個組件繪製子圖
            components.forEach((component, i) => {
                const yPos = margin.top + i * (subPlotHeight + 15);

                // 獲取該組件的所有數據點
                const componentData = component.data;

                // 計算 y 軸範圍
                const allValues = [];
                componentData.forEach(d => {
                    if (!isNaN(d.mean) && !isNaN(d.std)) {
                        allValues.push(d.mean - 3 * d.std);
                        allValues.push(d.mean + 3 * d.std);
                    }
                    if (!isNaN(d.sample1)) allValues.push(d.sample1);
                    if (!isNaN(d.sample2)) allValues.push(d.sample2);
                    if (!isNaN(d.sample3)) allValues.push(d.sample3);
                });

                const yExtent = d3.extent(allValues);
                const yPadding = (yExtent[1] - yExtent[0]) * 0.1;

                const yScale = d3.scaleLinear()
                    .domain([yExtent[0] - yPadding, yExtent[1] + yPadding])
                    .range([yPos + subPlotHeight, yPos]);

                // 創建子圖區域
                const subPlot = svg.append("g")
                    .attr("class", `subplot-${component.key}`);

                // 添加子圖背景
                subPlot.append("rect")
                    .attr("x", margin.left)
                    .attr("y", yPos)
                    .attr("width", containerWidth - margin.left - margin.right)
                    .attr("height", subPlotHeight)
                    .attr("fill", "#f9f9f9")
                    .attr("stroke", "#e0e0e0")
                    .attr("stroke-width", 1);

                // 添加 y 軸
                const yAxis = d3.axisLeft(yScale)
                    .ticks(4)
                    .tickSize(-5);

                subPlot.append("g")
                    .attr("class", "y-axis")
                    .attr("transform", `translate(${margin.left},0)`)
                    .call(yAxis)
                    .selectAll("text")
                    .style("font-size", "10px");

                // 只在最後一個子圖添加 x 軸
                if (i === numComponents - 1) {
                    const xAxis = d3.axisBottom(xScale)
                        .ticks(8)
                        .tickFormat(d => `${d}`);

                    subPlot.append("g")
                        .attr("class", "x-axis")
                        .attr("transform", `translate(0,${yPos + subPlotHeight})`)
                        .call(xAxis)
                        .selectAll("text")
                        .style("font-size", "10px");
                }

                // 添加子圖標題
                subPlot.append("text")
                    .attr("x", containerWidth / 2)
                    .attr("y", yPos - 5)
                    .attr("text-anchor", "middle")
                    .style("font-size", "12px")
                    .style("font-weight", "bold")
                    .style("fill", colors[component.key] || "#333")
                    .text(component.name);

                // 添加中心線 (y=0)
                if (i > 0) { // 不為 Input 添加零線
                    const zeroLineY = yScale(0);
                    if (yScale.domain()[0] <= 0 && yScale.domain()[1] >= 0) {
                        subPlot.append("line")
                            .attr("x1", margin.left)
                            .attr("x2", containerWidth - margin.right)
                            .attr("y1", zeroLineY)
                            .attr("y2", zeroLineY)
                            .attr("stroke", "grey")
                            .attr("stroke-width", 0.5)
                            .attr("stroke-dasharray", "3,3");
                    }
                }

                // 準備繪製線條和區域
                const lineGenerator = d3.line()
                    .x((d, i) => xScale(i))
                    .y(d => yScale(d.mean))
                    .defined(d => !isNaN(d.mean));

                // 創建不確定性區域 (99% Isoband)
                const area99 = d3.area()
                    .x((d, i) => xScale(i))
                    .y0(d => yScale(d.mean - sigmaLevels['99%'] * d.std))
                    .y1(d => yScale(d.mean + sigmaLevels['99%'] * d.std))
                    .defined(d => !isNaN(d.mean) && !isNaN(d.std));

                // 創建不確定性區域 (50% Isoband)
                const area50 = d3.area()
                    .x((d, i) => xScale(i))
                    .y0(d => yScale(d.mean - sigmaLevels['50%'] * d.std))
                    .y1(d => yScale(d.mean + sigmaLevels['50%'] * d.std))
                    .defined(d => !isNaN(d.mean) && !isNaN(d.std));

                // 繪製 99% 不確定性區域
                subPlot.append("path")
                    .datum(componentData.filter(d => !isNaN(d.mean) && !isNaN(d.std)))
                    .attr("fill", isoColors['99%'])
                    .attr("opacity", 0.3)
                    .attr("d", area99);

                // 繪製 50% 不確定性區域
                subPlot.append("path")
                    .datum(componentData.filter(d => !isNaN(d.mean) && !isNaN(d.std)))
                    .attr("fill", isoColors['50%'])
                    .attr("opacity", 0.5)
                    .attr("d", area50);

                // 繪製樣本線
                for (let s = 1; s <= numSamples; s++) {
                    const sampleKey = `sample${s}`;
                    const sampleLine = d3.line()
                        .x((d, i) => xScale(i))
                        .y(d => yScale(d[sampleKey]))
                        .defined(d => !isNaN(d[sampleKey]));

                    const sampleData = componentData.filter(d => !isNaN(d[sampleKey]));
                    if (sampleData.length > 0) {
                        subPlot.append("path")
                            .datum(componentData)
                            .attr("fill", "none")
                            .attr("stroke", sampleColors[(s - 1) % sampleColors.length])
                            .attr("stroke-width", 0.8)
                            .attr("opacity", 0.7)
                            .attr("d", sampleLine);
                    }
                }

                // 繪製平均線
                subPlot.append("path")
                    .datum(componentData)
                    .attr("fill", "none")
                    .attr("stroke", meanColor)
                    .attr("stroke-width", 1.5)
                    .attr("d", lineGenerator);

                // 如果有coPoint，繪製垂直線表示分割點
                if (coPoint !== null && coPoint >= 0 && coPoint < data.length) {
                    subPlot.append("line")
                        .attr("x1", xScale(coPoint))
                        .attr("x2", xScale(coPoint))
                        .attr("y1", yPos)
                        .attr("y2", yPos + subPlotHeight)
                        .attr("stroke", "black")
                        .attr("stroke-width", 2);
                }

                // 繪製底部相關性色帶（matlab風格：每格高度反映不確定性）
                const corrBarHeight = 15;
                const corrBarY = yPos + subPlotHeight + 5;

                componentData.forEach((d, idx) => {
                    if (!isNaN(d.corr) && !isNaN(d.std)) {
                        // 計算該點的不確定性高度（基於標準差）
                        const maxStd = d3.max(componentData, dd => dd.std) || 1;
                        const uncertaintyHeight = (d.std / maxStd) * corrBarHeight;

                        // 計算矩形的y位置和高度（向上或向下延伸）
                        let rectY, rectHeight;
                        if (d.corr >= 0) {
                            rectY = corrBarY;
                            rectHeight = uncertaintyHeight * Math.abs(d.corr);
                        } else {
                            rectY = corrBarY + uncertaintyHeight * Math.abs(d.corr);
                            rectHeight = uncertaintyHeight * Math.abs(d.corr);
                        }

                        subPlot.append("rect")
                            .attr("x", xScale(idx) - (containerWidth - margin.left - margin.right) / data.length / 2)
                            .attr("y", rectY)
                            .attr("width", Math.max(1, (containerWidth - margin.left - margin.right) / data.length))
                            .attr("height", Math.max(1, rectHeight))
                            .attr("fill", coolWarmColorScale(d.corr))
                            .attr("stroke", "none");
                    }
                });
            });

            // 在最底部添加X軸標籤
            svg.append("text")
                .attr("x", containerWidth / 2)
                .attr("y", containerHeight - 10)
                .attr("text-anchor", "middle")
                .style("font-size", "12px")
                .text("Time Index (Days since start)");

        }).catch(error => {
            console.error('Error loading UASTL data:', error);
        });

    }, [range]);

    return (
        <div style={{ width: '100%', height: '100%', overflow: 'hidden' }}>
            <svg ref={svgRef} width="100%" height="100%" style={{ display: 'block' }} />
        </div>
    );
}

export default UASTLChart;
